  const vehicleRecords: any[] = [];
  for (const v of vehicleData) {
    const vehicle = await prisma.vehicle.create({
      data: {
        vehicleNo: v.vehicleNo,
        type: v.type as any,
        capacity: v.capacity,
        driverName: v.driverName,
        driverPhone: v.driverPhone,
        driverLicense: v.driverLicense,
        conductorName: v.conductorName,
        conductorPhone: v.conductorPhone,
        fuelType: v.fuelType as any,
        insuranceExpiry: new Date("2026-03-31"),
        fitnessExpiry: new Date("2026-06-30"),
        permitExpiry: new Date("2027-01-01"),
        status: "ACTIVE" as any,
        tenantId,
      },
    });
    vehicleRecords.push(vehicle);
  }
  console.log(`[OK] ${vehicleRecords.length} Vehicles created`);

  // Transport Routes (10 routes)
  const routeData = [
    { name: "Route 1 - City Center", code: "R01", startLocation: "School", endLocation: "Railway Station", distance: 12.5, estimatedTime: 45, monthlyFee: 1500 },
    { name: "Route 2 - Civil Lines", code: "R02", startLocation: "School", endLocation: "Civil Lines", distance: 8.0, estimatedTime: 30, monthlyFee: 1200 },
    { name: "Route 3 - Gomti Nagar", code: "R03", startLocation: "School", endLocation: "Gomti Nagar", distance: 15.0, estimatedTime: 50, monthlyFee: 1800 },
    { name: "Route 4 - Indira Nagar", code: "R04", startLocation: "School", endLocation: "Indira Nagar", distance: 10.0, estimatedTime: 35, monthlyFee: 1400 },
    { name: "Route 5 - Aliganj", code: "R05", startLocation: "School", endLocation: "Aliganj", distance: 7.5, estimatedTime: 25, monthlyFee: 1100 },
    { name: "Route 6 - Mahanagar", code: "R06", startLocation: "School", endLocation: "Mahanagar", distance: 6.0, estimatedTime: 20, monthlyFee: 1000 },
    { name: "Route 7 - Chowk", code: "R07", startLocation: "School", endLocation: "Chowk", distance: 9.0, estimatedTime: 40, monthlyFee: 1300 },
    { name: "Route 8 - Alambagh", code: "R08", startLocation: "School", endLocation: "Alambagh", distance: 14.0, estimatedTime: 55, monthlyFee: 1700 },
    { name: "Route 9 - Chinhat", code: "R09", startLocation: "School", endLocation: "Chinhat", distance: 11.0, estimatedTime: 40, monthlyFee: 1500 },
    { name: "Route 10 - Vikas Nagar", code: "R10", startLocation: "School", endLocation: "Vikas Nagar", distance: 13.0, estimatedTime: 45, monthlyFee: 1600 },
  ];
  
  const routeRecords: any[] = [];
  for (const r of routeData) {
    const route = await prisma.route.create({
      data: { ...r, status: "ACTIVE", tenantId },
    });
    routeRecords.push(route);
  }
  console.log(`[OK] ${routeRecords.length} Routes created`);

  // Route Stops (5 stops per route = 50 stops)
  const stopNames = ["Main Market", "Hospital Chowk", "Police Station", "Temple Road", "Park Gate", "College Road", "Bus Stand", "Petrol Pump", "Bank Colony", "School Turn"];
  const routeStopRecords: any[] = [];
  for (let ri = 0; ri < routeRecords.length; ri++) {
    const route = routeRecords[ri];
    for (let si = 0; si < 5; si++) {
      const stop = await prisma.routeStop.create({
        data: {
          routeId: route.id,
          name: `${stopNames[(ri * 5 + si) % stopNames.length]} - R${ri + 1}`,
          pickupTime: `${7 + Math.floor(si * 0.3)}:${String((si * 10) % 60).padStart(2, "0")}`,
          dropTime: `${14 + Math.floor(si * 0.3)}:${String((si * 10) % 60).padStart(2, "0")}`,
          sequence: si + 1,
          tenantId,
        },
      });
      routeStopRecords.push(stop);
    }
  }
  console.log(`[OK] ${routeStopRecords.length} Route Stops created`);

  // Transport Assignments (assign 300 students to transport)
  for (let i = 0; i < 300 && i < studentRecords.length; i++) {
    const s = studentRecords[i];
    const routeIdx = i % routeRecords.length;
    const route = routeRecords[routeIdx];
    const vehicle = vehicleRecords[i % vehicleRecords.length];
    const stopIdx = routeIdx * 5 + (i % 5);
    const stop = routeStopRecords[stopIdx] || routeStopRecords[0];
    
    await prisma.transportAssignment.create({
      data: {
        studentId: s.id,
        studentName: `${s.firstName} ${s.lastName}`,
        classInfo: s.className,
        routeId: route.id,
        stopId: stop.id,
        vehicleId: vehicle.id,
        assignmentType: "BOTH",
        monthlyFee: route.monthlyFee || 1500,
        startDate: new Date("2025-04-01"),
        status: "ACTIVE",
        tenantId,
      },
    });
  }
  console.log("[OK] 300 Transport Assignments created");

  // Transport Settings
  await prisma.transportSetting.create({
    data: {
      tenantId,
      lateFinePerDay: 10,
      absentNotification: true,
      gpsTrackingEnabled: true,
      smsAlertEnabled: true,
      maxStudentsPerVehicle: 50,
    },
  });
  console.log("[OK] Transport Settings created");

  // ============ EXAM MODULE ============
  // Exams (3 exams: Unit Test 1, Half Yearly, Annual)
  const examData = [
    { name: "Unit Test 1", type: "UNIT_TEST", startDate: new Date("2025-07-15"), endDate: new Date("2025-07-25") },
    { name: "Half Yearly", type: "HALF_YEARLY", startDate: new Date("2025-10-01"), endDate: new Date("2025-10-15") },
    { name: "Annual Exam", type: "ANNUAL", startDate: new Date("2026-03-01"), endDate: new Date("2026-03-15") },
  ];

  const examRecords: any[] = [];
  for (const cls of classRecords) {
    for (const ex of examData) {
      const exam = await prisma.exam.create({
        data: {
          name: ex.name,
          type: ex.type,
          classId: cls.id,
          academicYearId: ayId,
          tenantId,
          startDate: ex.startDate,
          endDate: ex.endDate,
          resultType: "BOTH",
          isPublished: ex.name === "Unit Test 1", // Only first exam results published
        },
      });
      examRecords.push({ ...exam, className: cls.name });

      // Exam Subjects with max marks
      const classSubjects = subjectRecords.filter((s: any) => s.classId === cls.id);
      for (const sub of classSubjects) {
        const maxMarks = ex.type === "UNIT_TEST" ? 25 : (ex.type === "HALF_YEARLY" ? 50 : 100);
        const passingMarks = Math.floor(maxMarks * 0.33);
        await prisma.examSubject.create({
          data: {
            examId: exam.id,
            subjectId: sub.id,
            tenantId,
            maxMarks,
            passingMarks,
          },
        });
      }
    }
  }
  console.log(`[OK] ${examRecords.length} Exams created with subjects`);

  // Exam Schedules (for Unit Test 1 only - with rooms)
  const unitTestExams = examRecords.filter((e: any) => e.name === "Unit Test 1");
  const examScheduleRecords: any[] = [];
  for (const exam of unitTestExams) {
    const classSubjects = subjectRecords.filter((s: any) => s.classId === exam.classId);
    let dayOffset = 0;
    for (const sub of classSubjects) {
      const scheduleDate = new Date("2025-07-15");
      scheduleDate.setDate(scheduleDate.getDate() + dayOffset);
      const roomIdx = dayOffset % roomRecords.length;
      const schedule = await prisma.examSchedule.create({
        data: {
          examId: exam.id,
          subjectId: sub.id,
          tenantId,
          examDate: scheduleDate,
          startTime: "09:00",
          endTime: "11:00",
          roomId: roomRecords[roomIdx].id,
        },
      });
      examScheduleRecords.push(schedule);
      dayOffset++;
    }
  }
  console.log(`[OK] ${examScheduleRecords.length} Exam Schedules created`);

  // Seating Arrangements (for first 5 exam schedules as sample)
  let seatCount = 0;
  for (let i = 0; i < 5 && i < examScheduleRecords.length; i++) {
    const schedule = examScheduleRecords[i];
    const exam = unitTestExams.find((e: any) => e.id === schedule.examId);
    const classStudents = studentRecords.filter((s: any) => s.className === exam?.className);
    for (let j = 0; j < classStudents.length; j++) {
      await prisma.seatingArrangement.create({
        data: {
          examScheduleId: schedule.id,
          studentId: classStudents[j].id,
          tenantId,
          seatNo: `S${j + 1}`,
          roomId: schedule.roomId,
        },
      });
      seatCount++;
    }
  }
  console.log(`[OK] ${seatCount} Seating Arrangements created`);

  // Invigilator Assignments
  let invigilatorCount = 0;
  for (let i = 0; i < examScheduleRecords.length; i++) {
    const schedule = examScheduleRecords[i];
    const chiefTeacher = teacherRecords[i % teacherRecords.length];
    const assistantTeacher = teacherRecords[(i + 1) % teacherRecords.length];
    await prisma.invigilatorAssignment.create({
      data: { examScheduleId: schedule.id, teacherId: chiefTeacher.id, tenantId, role: "Chief" },
    });
    await prisma.invigilatorAssignment.create({
      data: { examScheduleId: schedule.id, teacherId: assistantTeacher.id, tenantId, role: "Assistant" },
    });
    invigilatorCount += 2;
  }
  console.log(`[OK] ${invigilatorCount} Invigilator Assignments created`);

  // Admit Cards (for all students in Unit Test 1)
  let admitCardCount = 0;
  for (const exam of unitTestExams) {
    const classStudents = studentRecords.filter((s: any) => s.className === exam.className);
    for (let i = 0; i < classStudents.length; i++) {
      await prisma.admitCard.create({
        data: {
          examId: exam.id,
          studentId: classStudents[i].id,
          tenantId,
          rollNo: classStudents[i].rollNumber || String(i + 1),
          isGenerated: true,
          generatedAt: new Date("2025-07-10"),
        },
      });
      admitCardCount++;
    }
  }
  console.log(`[OK] ${admitCardCount} Admit Cards created`);

  // Marks Entry + Result Summary (Unit Test 1 only - batched)
  let marksCount = 0;
  let resultCount = 0;
  for (const exam of unitTestExams) {
    const classSubjects = subjectRecords.filter((s: any) => s.classId === exam.classId);
    const classStudents = studentRecords.filter((s: any) => s.className === exam.className);
    
    const marksBatch: any[] = [];
    const resultBatch: any[] = [];

    for (const student of classStudents) {
      let totalMarks = 0;
      let totalMax = 0;
      let passedSubjects = 0;
      let failedSubjects = 0;

      for (const sub of classSubjects) {
        const maxMarks = 25;
        const marks = Math.floor(Math.random() * 20) + 5;
        const isAbsent = Math.random() < 0.02;
        
        marksBatch.push({
          examId: exam.id, studentId: student.id, subjectId: sub.id,
          tenantId, marksObtained: isAbsent ? 0 : marks, isAbsent,
        });
        
        if (!isAbsent) {
          totalMarks += marks; totalMax += maxMarks;
          if (marks >= Math.floor(maxMarks * 0.33)) passedSubjects++; else failedSubjects++;
        } else { totalMax += maxMarks; failedSubjects++; }
      }

      const percentage = totalMax > 0 ? (totalMarks / totalMax) * 100 : 0;
      let grade = "F";
      if (percentage >= 90) grade = "A+";
      else if (percentage >= 80) grade = "A";
      else if (percentage >= 70) grade = "B+";
      else if (percentage >= 60) grade = "B";
      else if (percentage >= 50) grade = "C";
      else if (percentage >= 33) grade = "D";

      resultBatch.push({
        examId: exam.id, studentId: student.id, tenantId, totalMarks,
        totalMaxMarks: totalMax, percentage: Math.round(percentage * 100) / 100,
        grade, status: failedSubjects === 0 ? "PASS" : "FAIL",
        totalSubjects: classSubjects.length, passedSubjects, failedSubjects,
      });
    }
    
    // Insert in chunks of 500
    for (let ci = 0; ci < marksBatch.length; ci += 500) {
      await prisma.marksEntry.createMany({ data: marksBatch.slice(ci, ci + 500) });
    }
    marksCount += marksBatch.length;
    
    await prisma.resultSummary.createMany({ data: resultBatch });
    resultCount += resultBatch.length;
    
    console.log(`  ... Marks for class ${exam.className} done (${marksBatch.length} marks, ${resultBatch.length} results)`);
  }
  console.log(`[OK] ${marksCount} Marks + ${resultCount} Results created`);

  // Grade Settings
  await prisma.gradeSetting.createMany({
    data: [
      { tenantId, grade: "A+", minPercent: 90, maxPercent: 100, gradePoint: 10, remarks: "Outstanding" },
      { tenantId, grade: "A", minPercent: 80, maxPercent: 89.99, gradePoint: 9, remarks: "Excellent" },
      { tenantId, grade: "B+", minPercent: 70, maxPercent: 79.99, gradePoint: 8, remarks: "Very Good" },
      { tenantId, grade: "B", minPercent: 60, maxPercent: 69.99, gradePoint: 7, remarks: "Good" },
      { tenantId, grade: "C", minPercent: 50, maxPercent: 59.99, gradePoint: 6, remarks: "Average" },
      { tenantId, grade: "D", minPercent: 33, maxPercent: 49.99, gradePoint: 5, remarks: "Below Average" },
      { tenantId, grade: "F", minPercent: 0, maxPercent: 32.99, gradePoint: 0, remarks: "Fail" },
    ],
  });
  console.log("[OK] Grade Settings created");

  // ============ ATTENDANCE (last 5 working days - batched) ============
  const today = new Date();
  let attendanceCount = 0;
  for (let dayOffset = 1; dayOffset <= 5; dayOffset++) {
    const date = new Date(today);
    date.setDate(date.getDate() - dayOffset);
    if (date.getDay() === 0) continue; // Skip Sunday

    // Batch create attendance per day
    const attendanceBatch = enrollmentRecords.map((enrollment: any) => ({
      studentId: enrollment.studentId,
      classId: enrollment.classId,
      sectionId: enrollment.sectionId,
      tenantId,
      academicYearId: ayId,
      date,
      status: Math.random() > 0.1 ? "PRESENT" : "ABSENT",
    }));
    
    // Split into chunks of 200 to avoid payload limits
    for (let ci = 0; ci < attendanceBatch.length; ci += 200) {
      const chunk = attendanceBatch.slice(ci, ci + 200);
      await prisma.attendance.createMany({ data: chunk as any });
      attendanceCount += chunk.length;
    }
    console.log(`  ... Attendance day -${dayOffset} done`);
  }
  console.log(`[OK] ${attendanceCount} Attendance records created`);

  // ============ TIMETABLE (batched) ============
  const days: ("MON" | "TUE" | "WED" | "THU" | "FRI" | "SAT")[] = ["MON", "TUE", "WED", "THU", "FRI", "SAT"];
  let timetableCount = 0;
  for (const cls of classRecords) {
    const classSections = sectionRecords.filter((s: any) => s.classId === cls.id);
    const classSubjects = subjectRecords.filter((s: any) => s.classId === cls.id);
    if (classSubjects.length === 0) continue;

    const timetableBatch: any[] = [];
    for (const section of classSections) {
      for (const day of days) {
        for (let period = 1; period <= 8; period++) {
          const subIdx = (period - 1) % classSubjects.length;
          const sub = classSubjects[subIdx];
          const teacherIdx = (timetableCount) % teacherRecords.length;
          timetableBatch.push({
            classId: cls.id,
            sectionId: section.id,
            subjectId: sub.id,
            teacherId: teacherRecords[teacherIdx].id,
            tenantId,
            day,
            period,
          });
          timetableCount++;
        }
      }
    }
    await prisma.timetable.createMany({ data: timetableBatch });
  }
  console.log(`[OK] ${timetableCount} Timetable entries created`);

  // ============ TEACHER SALARIES (3 months - batched) ============
  const salaryBatch: any[] = [];
  for (const teacher of teacherRecords) {
    const basicSalary = 25000 + Math.floor(Math.random() * 30000);
    for (let month = 4; month <= 6; month++) {
      const allowances = { HRA: basicSalary * 0.4, DA: basicSalary * 0.2, TA: 2000, Medical: 1500 };
      const deductions = { PF: basicSalary * 0.12, TDS: basicSalary * 0.05, Professional_Tax: 200 };
      const totalAllowances = Object.values(allowances).reduce((a: number, b: number) => a + b, 0);
      const totalDeductions = Object.values(deductions).reduce((a: number, b: number) => a + b, 0);
      const netSalary = basicSalary + totalAllowances - totalDeductions;
      salaryBatch.push({
        teacherId: teacher.id, month, year: 2025, basicSalary,
        allowances, deductions, totalAllowances, totalDeductions, netSalary,
        status: "PAID", paidAt: new Date(2025, month - 1, 28), tenantId, academicYearId: ayId,
      });
    }
  }
  await prisma.teacherSalary.createMany({ data: salaryBatch });
